import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonSyntaxException;
import com.google.gson.internal.bind.NumberTypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.ToNumberStrategy;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import java.io.IOException;
import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class NumberTypeAdapterTest {

    private NumberTypeAdapter adapter;
    private ToNumberStrategy toNumberStrategy;
    private JsonReader jsonReader;

    @BeforeEach
    public void setUp() throws Exception {
        toNumberStrategy = mock(ToNumberStrategy.class);
        jsonReader = mock(JsonReader.class);
        Constructor<NumberTypeAdapter> constructor = NumberTypeAdapter.class.getDeclaredConstructor(ToNumberStrategy.class);
        constructor.setAccessible(true);
        adapter = constructor.newInstance(toNumberStrategy);
    }

    @Test
    public void testRead_NullToken_ReturnsNull() throws IOException {
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        doNothing().when(jsonReader).nextNull();

        Number result = adapter.read(jsonReader);

        InOrder inOrder = inOrder(jsonReader);
        inOrder.verify(jsonReader).peek();
        inOrder.verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    public void testRead_NumberToken_DelegatesToStrategy() throws IOException {
        when(jsonReader.peek()).thenReturn(JsonToken.NUMBER);
        Number expectedNumber = 123.45;
        when(toNumberStrategy.readNumber(jsonReader)).thenReturn(expectedNumber);

        Number result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(toNumberStrategy).readNumber(jsonReader);
        assertEquals(expectedNumber, result);
    }

    @Test
    public void testRead_StringToken_DelegatesToStrategy() throws IOException {
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);
        Number expectedNumber = 99;
        when(toNumberStrategy.readNumber(jsonReader)).thenReturn(expectedNumber);

        Number result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(toNumberStrategy).readNumber(jsonReader);
        assertEquals(expectedNumber, result);
    }

    @Test
    public void testRead_InvalidToken_ThrowsJsonSyntaxException() throws IOException {
        when(jsonReader.peek()).thenReturn(JsonToken.BEGIN_OBJECT);
        when(jsonReader.getPath()).thenReturn("$.number");

        JsonSyntaxException exception = assertThrows(JsonSyntaxException.class, () -> adapter.read(jsonReader));

        assertTrue(exception.getMessage().contains("Expecting number, got: " + JsonToken.BEGIN_OBJECT));
        assertTrue(exception.getMessage().contains("$.number"));
        verify(jsonReader).peek();
        verify(jsonReader).getPath();
    }
}
